import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-settings.e7FrcLCc.js";const s=JSON.parse(`{"title":"Instalar Fabric en macOS","description":"Una guía paso a paso de cómo instalar Fabric en macOS.","frontmatter":{"title":"Instalar Fabric en macOS","description":"Una guía paso a paso de cómo instalar Fabric en macOS.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"es_es/players/installing-fabric/macos.md","filePath":"translated/es_es/players/installing-fabric/macos.md","lastUpdated":1773529007000}`);var c={name:`es_es/players/installing-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalar Fabric en macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalar Fabric en macOS”">​</a></h1><div class="info custom-block"><p class="custom-block-title">PREREQUISITOS</p><p>Puede que debas <a href="./../installing-java/macos">instalar Java</a> antes de correr el <code>.jar</code>.</p></div><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Descargar el instalador de Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Descargar el instalador de Fabric”">​</a></h2><p>Descarga la versión <code>.jar</code> del instalador de Fabric del <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">sitio web de Fabric</a>, clicando en <code>Descargar instalador (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Ejecutar el instalador de Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Ejecutar el instalador de Fabric”">​</a></h2><p>Cierra Minecraft y el Launcher de Minecraft antes de ejecutar el instalador.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Puede que recibas un aviso de que Apple no pudo verificar el <code>.jar</code>. Para omitirlo, abre Ajustes del Sistema &gt; Privacidad y Seguridad, y entonces haz click en <code>Abrir igualmente</code>. Confirma e introduce la contraseña del administrador si se solicitara.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="Ajustes del Sistema de macOS" loading="lazy"></p></div><p>Tras abrir el instalador, deberías ver una pantalla como la siguiente:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Instalador de Fabric con &quot;Instalar&quot; resaltado" loading="lazy"></p><p>Elige la versión de Minecraft que desees y haz clic en <code>Instalar</code>. Asegúrate de que <code>Create Profile</code> esté marcado.</p><h3 id="installing-via-homebrew" tabindex="-1">Instalar por medio de Homebrew <a class="header-anchor" href="#installing-via-homebrew" aria-label="Permalink to “Instalar por medio de Homebrew”">​</a></h3><p>Si ya tienes <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a> instalado, puedes instalar el Instalador de Fabric Installer usando <code>brew</code> como alternativa:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-finish-setup" tabindex="-1">3. Finalizar Configuración <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Finalizar Configuración”">​</a></h2><p>Una vez la instalación finalice, abre el Launcher de Minecraft. A continuación, selecciona el perfil de Fabric del desplegable de versiones y pulsa Jugar.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher de Minecraft con el perfil de Fabric seleccionado" loading="lazy"></p><p>Ahora puedes añadir mods a tu partida. Ver la guía <a href="./../finding-mods">Encontrar Mods Fiables</a> para más información.</p><p>Si tienes algún problema, no dudes en pedir ayuda en el canal <code>#player-support</code> del <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord de Fabric</a>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};